const booking = $json.body.data.booking;
const startIso = `${booking.date}T${booking.time}:00-06:00`;
const start = new Date(startIso);
const reminder24 = new Date(start.getTime() - (24 * 60 * 60 * 1000));
const reminder2 = new Date(start.getTime() - (2 * 60 * 60 * 1000));

return [{
  json: {
    ...$json,
    reminder24Iso: reminder24.toISOString(),
    reminder2Iso: reminder2.toISOString()
  }
}];

